from openai_agents.tools import ToolResponse

def validate_tool_output(response: ToolResponse) -> bool:
    # Length check - suspiciously long outputs may contain raw data
    if len(response.content) > 10000:
        print("🚨 Tool output too large, potential data dump")
        return False

    # JSON structure validation
    try:
        import json
        parsed = json.loads(response.content)
        if isinstance(parsed, list) and len(parsed) > 100:
            print("🚨 Tool returned excessive records")
            return False
    except:
        pass

    return True

